const results = $input.first().json.results || [];
const heute = new Date();
const heuteDe = heute.toLocaleDateString('de-DE');

const posts = results.map(page => {
  const props = page.properties;
  const titel = props?.['Titel']?.title?.[0]?.plain_text || 'Ohne Titel';
  const geplantFuer = props?.['Geplant für']?.date?.start || '';
  const saeule = props?.['Säule']?.select?.name || '-';
  const linkedin_post = props?.['LinkedIn-Post']?.rich_text?.[0]?.plain_text || '';
  const hatText = linkedin_post.trim().length > 0;

  let verzoegerungTage = 0;
  if (geplantFuer) {
    const geplant = new Date(geplantFuer);
    verzoegerungTage = Math.floor((heute - geplant) / (1000 * 60 * 60 * 24));
  }

  return { titel, geplantFuer, saeule, hatText, verzoegerungTage };
});

console.log(`⚠️ Content-Gap: ${posts.length} überfällige Post(s) gefunden`);

const postListHtml = posts.map(p => {
  const datum = p.geplantFuer
    ? new Date(p.geplantFuer).toLocaleDateString('de-DE')
    : 'kein Datum';
  const verz = p.verzoegerungTage > 0 ? ` – <strong style="color:#c53030">${p.verzoegerungTage} Tag(e) überfällig</strong>` : '';
  const textStatus = p.hatText
    ? '<span style="color:#276749">✓ Text vorhanden</span>'
    : '<span style="color:#c53030">✗ Kein Text</span>';
  return `<li><strong>${p.titel}</strong> (${p.saeule})${verz}<br><small>Geplant für: ${datum} · ${textStatus}</small></li>`;
}).join('');

const ohnText = posts.filter(p => !p.hatText).length;
const mitText = posts.filter(p => p.hatText).length;

return [{
  json: {
    to: 'wolfgang.baierl@blboardsolutions.de',
    subject: `[LinkedIn] ${posts.length} überfällige(r) Post(s) – Handlungsbedarf`,
    body: `<div style="font-family:Arial,sans-serif;max-width:600px">
<h2 style="color:#c53030">Content-Gap entdeckt – ${posts.length} Post(s) überfällig</h2>
<p>Folgende Posts haben ihr geplantes Datum überschritten und sind noch nicht veröffentlicht:</p>
<ul style="line-height:2">${postListHtml}</ul>
<hr style="margin:20px 0">
<table style="width:100%;border-collapse:collapse;margin-bottom:20px">
  <tr><td style="padding:6px;background:#f7fafc">Überfällige Posts gesamt:</td><td style="padding:6px;font-weight:bold">${posts.length}</td></tr>
  <tr><td style="padding:6px;background:#f7fafc">Davon ohne Text:</td><td style="padding:6px;font-weight:bold;color:#c53030">${ohnText}</td></tr>
  <tr><td style="padding:6px;background:#f7fafc">Davon mit Text (nur noch posten):</td><td style="padding:6px;font-weight:bold;color:#276749">${mitText}</td></tr>
</table>
<p><strong>Empfohlene Maßnahmen:</strong></p>
<ul>
  <li>Posts ohne Text: Post-Text-Generator-Workflow ausführen oder manuell verfassen</li>
  <li>Posts mit Text: Sofort veröffentlichen oder Datum anpassen</li>
  <li>Alternativ: Status auf <em>Pausiert</em> setzen, wenn der Post nicht mehr aktuell ist</li>
</ul>
<p><a href="https://www.notion.so/35147c762802803f8311ce87bcce27a5" style="background:#c53030;color:#fff;padding:10px 20px;text-decoration:none;border-radius:4px;display:inline-block">→ Content Pipeline öffnen</a></p>
<p style="color:#999;font-size:0.8em;margin-top:30px">Automatisch generiert am ${heuteDe} · n8n LinkedIn-Workflow</p>
</div>`
  }
}];
